def encode(message):
    vowel_map = {
        'a': 'c', 'e': 'g', 'i': 'k', 'o': 'q', 'u': 'w',
        'A': 'C', 'E': 'G', 'I': 'K', 'O': 'Q', 'U': 'W'
    }

    encoded = []
    for ch in message:
        swapped = ch.swapcase()
        encoded.append(vowel_map.get(swapped, swapped))

    return ''.join(encoded)
