def count_up_to(n):
    if n <= 2:
        return []

    sieve = [True] * n
    sieve[0] = sieve[1] = False

    limit = int(n ** 0.5) + 1
    for i in range(2, limit):
        if sieve[i]:
            for j in range(i * i, n, i):
                sieve[j] = False

    return [i for i, is_prime in enumerate(sieve) if is_prime]
```

